var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REPLY_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나 이 로봇 알아. 그라운드 원에서 정기 안전 교육 할 때 본 적 있음.</color>","JPN":"<color=#ffd34c>このロボット見たことある。グラウンド・ワンで定期安全教育訓練の時見た。</color>","ENG":"<color=#ffd34c>I know this robot. I saw him at the Ground One regular safety training.</color>","TWN":"<color=#ffd34c>我知道這個機器人，在 G1 進行定期安全教育時見過。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"REPLY_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>무슨 작은 태스크포스 사장님이라고 그러던데?</color>","JPN":"<color=#ffd34c>どっかの小規模タスクフォースの社長って聞いたよ。</color>","ENG":"<color=#ffd34c>I heard he’s a CEO of a small TASKFORCE company.</color>","TWN":"<color=#ffd34c>聽說是一家小小特遣勢力公司的老闆？</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"REPLY_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나 캄파멘토에서 일하는데 위에 진심?</color>","JPN":"<color=#ffd34c>俺、カンパメントで働いてるけど、↑マジか？</color>","ENG":"<color=#ffd34c>I work in Campamento, are you for real?</color>","TWN":"<color=#ffd34c>我在坎帕門托工作，樓上認真？</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흐응……. 그럴 줄 알았어. 그라운드 원의 사장님이었잖아.","JPN":"へえ、やっぱりな。グラウンド・ワンの社長だったんだ。","ENG":"Hmm... I knew it. He’s the CEO from Ground One.","TWN":"嗯… 我就知道會這樣，原來是 G1 的老闆。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"이런…… 빌어먹을!","JPN":"……くそ！","ENG":"Darn it!","TWN":"糟糕… 該死的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"왜 갑자기 성질이야, 아저씨? 또 데이팅 앱에서 차였어?","JPN":"急にどうしたの、おっさん。またマッチングアプリでブロックでもされたか？","ENG":"Why are you so upset, old man? Got dumped on a dating app again?","TWN":"大叔幹嘛突然發火？又在交友軟體上被甩啦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"바보 같은 소리 작작하고 이거나 봐!","JPN":"馬鹿を言うんじゃねえ。これを見ろ！","ENG":"Shut up and look at this!","TWN":"少說廢話，你看這個！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그 멍청한 펭귄들이랑 꼬맹이들이 찍은 영상이야!","JPN":"あのペンギンどもとガキどもが撮った映像だ！","ENG":"It’s a video with those stupid penguins and kids!","TWN":"這是那些笨企鵝和小鬼們拍的影片！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"우리가 바이럴 업체에 의뢰해서 여론 조작했던 게 죄다 수포로 돌아갔다고!","JPN":"俺らがバイラル広告代理店に依頼して情報操作をしたことがすべてパーになっちまったんだよ！","ENG":"All the work we did with viral companies to taint the village’s reputation is gone now!","TWN":"我們委託霉體公司操弄輿論的計畫都毀啦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하아, 그 촌티 나는 꼬맹이도 있네? 포기 안 한 건가?","JPN":"へー、あの田舎臭いガキもいるじゃん。まだ諦めてないんだ？","ENG":"Oh, there’s that lame kid. So they haven’t given up yet?","TWN":"哈，那個土包子小鬼也在喔？還沒放棄嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"처음부터 말도 안 되는 계획이었어. 헛소문을 흘려서 쫓아내겠다니.","JPN":"最初からでたらめな計画だったんだ。デマを流して追い出すなんて。","ENG":"It was never going to work. Spreading rumors won’t drive them away.","TWN":"這個計畫從一開始就很荒謬，怎麼可能靠著散播謠言把村民趕走！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐래. 좋다고 할 땐 언제고 이제 와서 딴소리야.","JPN":"は？　いいアイデアって言ったくせに今更？","ENG":"What? You agreed, and now you’re complaining?","TWN":"你說什麼？那時候明明你也同意的，現在才在馬後炮。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"내가 아니라 클라이언트가 문제야.","JPN":"俺じゃなくて、クライアントが問題だ。","ENG":"I’m not the problem, it’s the client.","TWN":"重點不是我，重點是客戶！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"방금 막 연락이 왔다. <color=#ffd34c>그 녀석</color>을 쓰라고 말이야.","JPN":"ちょうど今連絡が来た。<color=#ffd34c>あいつ</color>を使えと。","ENG":"They just called. They want us to use <color=#ffd34c>it</color>.","TWN":"剛剛收到消息，要出動<color=#ffd34c>那個東西</color>！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"앙? 그로니아에서 반군 놈들이 빼돌렸다던 그거 말야?","JPN":"あ？　グロニアで反乱軍の連中が引き抜いたアレか？","ENG":"Huh? The device that Gronia rebels stole?","TWN":"嗯？在格羅尼亞被叛軍偷走的那個嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그래. 기한을 넘기면 피 보는 건 우리야. 너도 그렇게 알고 있어.","JPN":"ああ。期限を過ぎるとヤバいことになるのは俺らだ。","ENG":"Yes. It’ll be on us if we don’t finish the job in time. You remember that.","TWN":"沒錯，萬一沒達成客戶的委託，到時候你跟我們都要倒大楣！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"거기 멈춰. 아저씨.","JPN":"待って、おっさん。","ENG":"Stop right there, old man.","TWN":"等一下，大叔。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"왜, 또 네 잘난 셀카라도 자랑하려고?","JPN":"なんだ、また自撮りでも自慢したくなったのか？","ENG":"Why? You’re showing me another selfie?","TWN":"幹嘛，又要炫耀你的自拍照？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"좋아요도 안 눌러 주는 아저씨 따위한테 내가 왜?","JPN":"イイねも押してくれないおっさんなんかに？","ENG":"Why would I do that, when you don’t even hit the Like button?","TWN":"對連點贊都不點的大叔，我幹嘛浪費時間炫耀？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"결국 <color=#ffd34c>제대로 된 침식체</color>라면 클라이언트도 마음을 바꿀 거란 뜻이지?","JPN":"結局<color=#ffd34c>まともな侵食体</color>ならクライアントも気を変えるという意味だろ？","ENG":"So what you’re saying is that bringing in <color=#ffd34c>proper C.O.s</color> will change the client’s mind, right?","TWN":"意思是，如果是<color=#ffd34c>正常版的侵蝕體</color>，那麼客戶可能會改變心意對吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"흥. 네 말대로 제대로 된 침식체라면 그렇겠지.","JPN":"ふん。本当にまともな侵食体なら、そうだろう。","ENG":"Hmpf... Maybe they will, if “proper” C.O.s appear.","TWN":"嗯，前提是你說的正常版侵蝕體。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"하지만 그 음침녀가 할 수 있을 거라고 생각하냐?","JPN":"でもあの陰気な女にできると思うのか？","ENG":"But do you think the creepy woman can actually do it?","TWN":"不過你認爲那個陰沉女辦得到嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"글쎄. 할 수 있을지 없을지는 두고 보면 알게 되겠지.","JPN":"さあね。できるかどうかは後でわかるっしょ。","ENG":"Well. I don’t know, but let’s wait and see.","TWN":"這個嘛，能不能做到，之後就會知道囉～"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"어차피 아저씨도 백날 허세 부려 봤자 그건 쓰기 찜찜하잖아?","JPN":"どうせおっさんも強がったって、アレを使うのは気が進まないだろ？","ENG":"Plus, I know you’re not really keen to use the device, old man.","TWN":"反正你也不敢碰那個東西不是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……드, 드라코 씨! 어디 있다가 이제 왔어요!","JPN":"……ド、ドラコさん！　どこにいたんですか！","ENG":"D-Dracasia! Where have you been?","TWN":"……德…德拉克！你怎麼現在才回來！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"초콜릿 침식체는 전부 만들어 줬잖아요. 이제 어서 절 풀어 달라고 해 주세요.","JPN":"チョコレート侵食体は要望どおりに作ってあげたじゃないですか。早く私を解放してと伝えてください。","ENG":"I made you all the chocolate C.O.s you wanted. Please let me go now.","TWN":"巧克力侵蝕體我都做完了，快叫他們放了我。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"미안, 미안. 일이 조금 많이 꼬여서 약속을 지키기는 어렵겠어.","JPN":"ごめん、ごめん。ちょっと色々こじれちゃって約束を守るのが難しくなったわ。","ENG":"I’m sorry, but the situation has changed and I can’t keep the promise.","TWN":"抱歉，抱歉。事情變得有點複雜，可能還不能放你走。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그, 그런 법이 어딨어……! 침식체를 만들면 여기서 풀려날 거라고 했잖아요!","JPN":"そ、そんなのひどい……！　侵食体を作ればここから解放してくれると言ったじゃないですか！","ENG":"N-no! You told me you’d let me go if I made you C.O.s!","TWN":"哪…哪有這種事……！你不是說如果做出侵蝕體，就會放我走嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"응? 박사님 범죄자 신분이잖아?","JPN":"え？　博士って犯罪者だろ？","ENG":"Huh? Doctor, you’re a criminal. Or did you forget?","TWN":"嗯？我記得博士你是罪犯吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그냥 확 신고해 버린다? 이번에 들어가면 몇 년이나 썩으려나?","JPN":"通報していいの？　次刑務所に入ったら何年過ごすことになるんだっけ？","ENG":"Shall I call the cops? Do you want to go back to prison?","TWN":"要我報警抓你嗎？這次再被抓進去，不知道要關幾年喔？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"읏…….","JPN":"うっ……","ENG":"Ugh...","TWN":"唔…"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아무튼, 좀 더 무서운 침식체를 만들어 줘야겠어.","JPN":"とにかく、もうちょっと怖い侵食体を作ってもらうことになったから。","ENG":"Well, I need you to make me scarier C.O.s.","TWN":"反正就是需要你做出更可怕的侵蝕體！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그 펭귄들은 얼치기라서 주민들이 무서워하기는커녕 애완동물로 여기거든.","JPN":"前のペンギンたちはマヌケすぎて、住民が怖がるどころかペットだと思ってんだよ。","ENG":"These stupid penguins scare no one. People think they’re pets.","TWN":"因爲那些企鵝都是二百五，居民根本不怕，甚至還把他們當成是寵物咧。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"나, 이제 그런 거 만들 생각 없어요. 그러다 누가 다치기라도 하면 어쩌려고요.","JPN":"もうそういうのを作るつもりはありません。誰かが怪我でもしたらどうするつもりですか。","ENG":"I don’t want to make any more C.O.s. I don’t want to hurt anyone.","TWN":"我不想做出那種東西，萬一有人因此受傷怎麼辦？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"박사님, 나도 이 의뢰 괜히 받았다 싶거든?","JPN":"博士、あたしだってこの依頼を受けたのを後悔してんだぞ？","ENG":"Doctor, I’m starting to regret taking this contract.","TWN":"博士，我也覺得根本不該接受這個委託。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그런데 이미 발 빼긴 늦었어. 클라이언트가 그 녀석을 쓰라고 했단 말이야.","JPN":"でも、もう身を引くには遅い。クライアントにあいつを使えと言われてたんだよ。","ENG":"But it’s too late now. The client wants us to use “it”.","TWN":"但頭都已經洗一半了，現在客戶說要出動那個東西。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그 녀석이라면……?","JPN":"あいつというのは……？","ENG":"“It”?","TWN":"那個東西…？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"맞아. 쓰기에 따라선 저런 작은 마을 따위 순식간에 날려 버릴 수 있는 무기지.","JPN":"そうだな。使い方によってはあんな小さな村なんか一瞬で吹き飛ばせる武器さ。","ENG":"Yes. With that device, we can crush that little village in no time.","TWN":"沒錯，就是可以瞬間剷平那個小村莊的武器。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"계속 못 하겠다고 버티면 어떻게 될지, 똑똑한 박사님이 나보다 더 잘 알잖아?","JPN":"だから、できないと意地を張ったらどうなるか、賢い博士ならわかってんだろ？","ENG":"You know what the client will do if we don’t finish the contract, right?","TWN":"如果你不想做我也不能逼你，但你這麼聰明，應該知道下場會如何吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"……쳇. 기분 더럽네, 진짜.","JPN":"……ちぇっ。胸くそ悪いな、ったく。","ENG":"... Dang, I feel so bad about it too.","TWN":"…嗟，真討厭！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"알아서 꺼지는 게 제일 낫다는 걸 왜 모르는 거야.","JPN":"さっさと消えるのが一番お互いのためになるのに、なんでわかってくれねぇんだよ。","ENG":"Why don’t they understand, just leaving the town is better for them?","TWN":"為什麼就是不能自己知難而退呢！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};